import { useEffect, useState } from "react";
import API_URL from "../api"; // Import the API base URL

function Home() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCapsules = async () => {
      try {
        const token = localStorage.getItem("token"); // Get the token from localStorage
        const response = await fetch(`${API_URL}/api/memoryhaven`, {
          headers: {
            Authorization: `Bearer ${token}`, // Include the token in the request
          },
        });

        if (!response.ok) {
          throw new Error("Failed to fetch capsules.");
        }

        const data = await response.json();
        setCapsules(data);
      } catch (error) {
        console.error("Error fetching capsules:", error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchCapsules();
  }, []);

  return (
    <div>
      <h1>Welcome to Memory Haven</h1>
      <p>Save the present, gift it to the future!</p>

      <h2>Recent Capsules</h2>
      {loading ? (
        <p>Loading...</p>
      ) : error ? (
        <p>Error: {error}</p>
      ) : capsules.length > 0 ? (
        <ul>
          {capsules.map((capsule) => (
            <li key={capsule._id}>
              <h3>{capsule.title}</h3>
              <p>{capsule.description}</p>
            </li>
          ))}
        </ul>
      ) : (
        <p>No capsules found. Create one now!</p>
      )}
    </div>
  );
}

export default Home;
